/* CSS Button Styling (Separated from Inline Styles) */
.btn-style-1 {
  width: auto;
  height: auto;
  padding: 4px 12px;
  background: #ffffff;
  border-radius: 999px;
  outline: 1px #DEDEDE solid;
  outline-offset: -1px;
  justify-content: flex-start;
  align-items: center;
  gap: 2px;
  display: inline-flex;
  cursor: pointer;
  transition: all 0.2s ease;
}

.btn-style-1:active {
  background-color: #f5f5f5;
  transform: scale(0.97);
}

.btn-style-1 .icon-container {
  width: 16px;
  height: 16px;
  position: relative;
  flex-shrink: 0;
}

.btn-style-1 .icon-shape {
  width: 7.40px;
  height: 5.80px;
  left: 4.30px;
  top: 5.10px;
  position: absolute;
  background: #212121;
}

.btn-style-1 .btn-text {
  text-align: center;
  color: #212121;
  font-size: 12px;
  font-family: 'Pretendard', -apple-system, sans-serif;
  font-weight: 500;
  line-height: 18px;
}
